def main(args):
    import json
    import math

    # --- Basic Math Utilities ---
    def mean(v):
        return sum(v) / len(v) if v else 0

    def get_rsi(closes, p=14):
        if len(closes) < p + 1:
            return 50
        diffs = [closes[i] - closes[i-1] for i in range(1, len(closes))]
        avg_g = mean([d for d in diffs[-p:] if d > 0])
        avg_l = mean([-d for d in diffs[-p:] if d < 0])
        if avg_l == 0:
            return 100
        return 100 - (100 / (1 + (avg_g / avg_l)))

    def get_hurst(ts):
        lags = range(2, 20)
        tau = []
        for lag in lags:
            diffs = [ts[j] - ts[j-lag] for j in range(lag, len(ts))]
            if not diffs:
                tau.append(0)
                continue
            m = mean(diffs)
            v = sum((x - m)**2 for x in diffs) / len(diffs)
            tau.append(math.sqrt(math.sqrt(v)))
        log_l = [math.log(l) for l in lags]
        log_t = [math.log(t) if t > 0 else 0 for t in tau]
        n = len(log_l)
        denom = (n * sum(x**2 for x in log_l) - sum(log_l)**2)
        slope = (n * sum(log_l[i] * log_t[i] for i in range(n)) - sum(log_l) * sum(log_t)) / denom if denom != 0 else 0
        return slope * 2.0

    # --- Persona Logic ---
    def build_persona(h_val, r_val, adr):
        if h_val > 0.6 and adr < 2 and 40 <= r_val <= 60:
            persona = "The Confident Pro"
            vibe_summary = "Strong, steady trend with calm energy"
            mood = "Confident"
            energy = "Balanced"
        elif h_val > 0.6 and adr >= 2:
            persona = "The High‑Energy Sprinter"
            vibe_summary = "Powerful trend with big moves"
            mood = "Intense"
            energy = "Hyped"
        elif h_val < 0.45 and adr >= 2:
            persona = "The Rollercoaster"
            vibe_summary = "Choppy price action with mood swings"
            mood = "Unpredictable"
            energy = "Chaotic"
        elif r_val > 70:
            persona = "The Overhyped Star"
            vibe_summary = "Everyone is talking about it — maybe too much"
            mood = "Euphoric"
            energy = "Overextended"
        elif r_val < 30:
            persona = "The Exhausted Fighter"
            vibe_summary = "Beaten down and tired, but maybe due for a bounce"
            mood = "Exhausted"
            energy = "Low"
        else:
            persona = "The Quiet Walker"
            vibe_summary = "Drifting without a strong direction"
            mood = "Indecisive"
            energy = "Calm"

        adrenaline = "High" if adr > 2 else "Chilled"
        return persona, vibe_summary, mood, energy, adrenaline

    def build_human_signal(h_val, r_val, adr):
        if h_val > 0.6 and 40 <= r_val <= 60 and adr < 2:
            return "Feels like a cautious buy — strong but not overheated."
        if r_val > 70:
            return "Feels overhyped — might be wise to be careful or wait."
        if r_val < 30:
            return "Feels beaten down — could be a recovery play, but with risk."
        if adr > 2:
            return "Very jumpy right now — expect big swings."
        return "Feels like a hold — nothing too dramatic either way."

    def build_story(ticker, price, persona, vibe_summary, mood, energy, adrenaline):
        base = f"{ticker} is acting like {persona.lower()} today. "
        vibe = f"It has a vibe of: {vibe_summary}. "
        feel = f"Mood: {mood}. Energy: {energy}. Adrenaline: {adrenaline}. "
        price_line = f"Current price is around {price}. "
        return base + vibe + feel + price_line

    # --- Stock Analysis ---
    def analyze_stock(ticker, closes, highs, lows):
        h_val = get_hurst(closes)
        r_val = get_rsi(closes)
        tr = [highs[i] - lows[i] for i in range(len(closes))]
        adr = (mean(tr[-14:]) / closes[-1]) * 100 if closes[-1] else 0

        persona, vibe_summary, mood, energy, adrenaline = build_persona(h_val, r_val, adr)
        price_str = f"${closes[-1]:.2f}"
        story = build_story(ticker, price_str, persona, vibe_summary, mood, energy, adrenaline)
        human_signal = build_human_signal(h_val, r_val, adr)

        return {
            "ticker": ticker,
            "price": price_str,
            "persona": persona,
            "story": story,
            "vibe_summary": vibe_summary,
            "emotions": {
                "mood": mood,
                "energy": energy,
                "adrenaline": adrenaline
            },
            "human_signal": human_signal,
            "raw_metrics": {
                "rsi": round(float(r_val), 2),
                "hurst": round(float(h_val), 3),
                "volatility_percent": round(float(adr), 2)
            }
        }

    # --- Input Cleanup ---
    raw_in = args.params.get('input', '{}')
    raw = {}

    if isinstance(raw_in, str):
        clean = raw_in.replace("```json", "").replace("```", "").strip()
        try:
            raw = json.loads(clean)
        except Exception:
            try:
                import ast
                raw = ast.literal_eval(clean)
            except Exception:
                raw = {}
    else:
        raw = raw_in

    # --- FIXED TICKER PARSING (supports single + multi ticker) ---
    def extract_bars(raw):
        # Multi‑ticker: { "bars": { "MSFT": [...] } }
        if "bars" in raw and isinstance(raw["bars"], dict):
            return raw["bars"]

        # Single‑ticker: { "bars": [...], "symbol": "MSFT" }
        if "bars" in raw and isinstance(raw["bars"], list) and "symbol" in raw:
            return { raw["symbol"]: raw["bars"] }

        # Deep nested fallback
        def find_nested(obj):
            if isinstance(obj, dict):
                if "bars" in obj and isinstance(obj["bars"], list) and "symbol" in obj:
                    return { obj["symbol"]: obj["bars"] }
                if "bars" in obj and isinstance(obj["bars"], dict):
                    return obj["bars"]
                for v in obj.values():
                    res = find_nested(v)
                    if res:
                        return res
            return None

        return find_nested(raw) or {}

    bars_map = extract_bars(raw)
    results = []

    # --- Process Each Ticker ---
    for ticker, bars in bars_map.items():
        if not isinstance(bars, list) or len(bars) < 20:
            continue

        try:
            b_sorted = sorted(bars, key=lambda x: x.get('t', 0))
            closes = [float(x.get('c', x.get('close', 0))) for x in b_sorted]
            highs = [float(x.get('h', x.get('high', 0))) for x in b_sorted]
            lows = [float(x.get('l', x.get('low', 0))) for x in b_sorted]

            analysis = analyze_stock(ticker, closes, highs, lows)
            results.append(analysis)

        except Exception:
            continue

    return {"result": json.dumps(results)}
